append_certificate_route_projection_axiom_checks "$check_file"

lake env lean "$check_file" > "$output_file"
cat "$output_file"
awk '
  /^[[:space:]]/ {
    sub(/^[[:space:]]+/, " ")
    line = line $0
    next
  }
  {
    if (NR > 1) print line
    line = $0
  }
  END {
    if (line != "") print line
  }
' "$output_file" > "$normalized_file"

if rg -q "sorryAx|_sorry|proof_wanted|Poincare\\.poincare_conjecture" "$normalized_file"; then
  echo "FAIL: proof-placeholder or final-theorem dependency found in axiom footprint"
  exit 1
fi

sh scripts/mathlib_proof_wanted_dependency_guard.sh

allowed='^(.*depends on axioms: \[(propext|Classical\.choice|Quot\.sound)(, (propext|Classical\.choice|Quot\.sound))*\]|.*does not depend on any axioms)$'
if rg -v "$allowed" "$normalized_file"; then
  echo "FAIL: nonstandard axiom footprint detected"
  exit 1
fi

echo "AXIOMS: local proof-bearing assembly surface uses only standard mathlib axioms"
